import os
import sys
import json
import argparse
import numpy as np
from collections import deque
from cogniplan_env import ExplorationEnv


def round_coords(coords, precision=1):
    return (round(coords[0], precision), round(coords[1], precision))


class ExplorationPlanner:
    def __init__(self, alpha=1.0, alpha_slope=2.0, visited_penalty=0.5,
                 neighbor_util_weight=0.8, use_euclidean=False):
        self.alpha = alpha
        self.alpha_slope = alpha_slope
        self.visited_penalty = visited_penalty
        self.neighbor_util_weight = neighbor_util_weight
        self.use_euclidean = use_euclidean
        self.visited_positions = set()
        self.step_count = 0

    def reset(self):
        self.visited_positions = set()
        self.step_count = 0

    def select_waypoint(self, obs):
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        robot_pos = obs['robot_pos']
        robot_pos_r = round_coords(robot_pos)
        explored_rate = obs['explored_rate']

        self.visited_positions.add(robot_pos_r)
        self.step_count += 1

        if not neighbors:
            return None

        # Build graph and node lookup
        graph = {}
        node_by_coords = {}
        for node in nodes:
            coords = round_coords(node['coords'])
            node_by_coords[coords] = node
            graph[coords] = [round_coords(n) for n in node['neighbors']]

        # Find start node (closest graph node to robot)
        start = robot_pos_r
        if start not in graph:
            min_dist = float('inf')
            for coords in graph:
                d = (coords[0] - robot_pos_r[0])**2 + (coords[1] - robot_pos_r[1])**2
                if d < min_dist:
                    min_dist = d
                    start = coords

        # BFS from start to compute distances and predecessors
        bfs_distances = {start: 0}
        predecessors = {start: None}
        queue = deque([start])
        while queue:
            current = queue.popleft()
            for nbr in graph.get(current, []):
                if nbr not in bfs_distances:
                    bfs_distances[nbr] = bfs_distances[current] + 1
                    predecessors[nbr] = current
                    queue.append(nbr)

        # Compute aggregated utilities (include neighbor utility)
        agg_utils = {}
        for node in nodes:
            coords = round_coords(node['coords'])
            util = float(node['utility'])
            for nbr_coords in graph.get(coords, []):
                nbr_node = node_by_coords.get(nbr_coords)
                if nbr_node:
                    util += self.neighbor_util_weight * float(nbr_node['utility'])
            agg_utils[coords] = util

        # Adaptive alpha - increases with explored_rate
        eff_alpha = self.alpha + self.alpha_slope * explored_rate

        # Score reachable neighbor nodes
        best_score = -float('inf')
        best_target = None

        for nbr in neighbors:
            nbr_r = round_coords(nbr)
            if nbr_r not in bfs_distances:
                continue

            if self.use_euclidean:
                dist = ((nbr[0] - robot_pos[0])**2 + (nbr[1] - robot_pos[1])**2) ** 0.5
                if dist < 0.1:
                    continue
            else:
                dist = float(bfs_distances[nbr_r])
                if dist == 0:
                    continue

            util = agg_utils.get(nbr_r, 0)

            # Visited penalty
            if nbr_r in self.visited_positions:
                util *= (1.0 - self.visited_penalty)

            if util <= 0:
                continue

            score = util / (dist ** eff_alpha)
            if score > best_score:
                best_score = score
                best_target = nbr

        # Fallback: if no neighbor has utility, navigate toward best graph node
        if best_target is None:
            best_graph_score = -float('inf')
            best_graph_node = None

            for coords, bfs_dist in bfs_distances.items():
                if bfs_dist == 0:
                    continue
                util = agg_utils.get(coords, 0)
                # No visited penalty in fallback - need to traverse visited nodes
                if util <= 0:
                    continue
                score = util / (bfs_dist ** eff_alpha)
                if score > best_graph_score:
                    best_graph_score = score
                    best_graph_node = coords

            if best_graph_node is not None:
                # Trace back through predecessors to find next step
                node = best_graph_node
                while predecessors.get(node) is not None and predecessors[node] != start:
                    node = predecessors[node]
                if node != start:
                    # Find matching neighbor (with fuzzy matching)
                    best_match_dist = float('inf')
                    for n in neighbors:
                        n_r = round_coords(n)
                        d = (n_r[0] - node[0])**2 + (n_r[1] - node[1])**2
                        if d < best_match_dist:
                            best_match_dist = d
                            best_target = n

        # Last resort: pick any unvisited neighbor, then any neighbor
        if best_target is None:
            for nbr in neighbors:
                nbr_r = round_coords(nbr)
                if nbr_r not in self.visited_positions:
                    best_target = nbr
                    break
            if best_target is None and neighbors:
                best_target = neighbors[0]

        return best_target


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for step in range(128):
        target = planner.select_waypoint(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info['done']:
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    # Load config
    config_path = os.path.join(args.checkpoint, 'config.json')
    with open(config_path) as f:
        config = json.load(f)

    # Load eval config
    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path) as f:
        eval_config = json.load(f)

    # Find all eval maps
    maps_dir = os.path.join(args.data_path, 'maps_eval')
    map_list = []
    for env_type in ['room', 'tunnel', 'outdoor']:
        type_dir = os.path.join(maps_dir, env_type)
        if os.path.isdir(type_dir):
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith('.png'):
                    map_list.append((os.path.join(env_type, fname), env_type))

    # Run evaluation
    per_episode = []
    for map_rel_path, env_type in map_list:
        map_path = os.path.join(maps_dir, map_rel_path)
        env = ExplorationEnv(map_path=map_path)
        planner = ExplorationPlanner(
            alpha=config.get('alpha', 1.0),
            alpha_slope=config.get('alpha_slope', 2.0),
            visited_penalty=config.get('visited_penalty', 0.5),
            neighbor_util_weight=config.get('neighbor_util_weight', 0.8),
            use_euclidean=config.get('use_euclidean', False),
        )
        metrics = run_episode(env, planner)
        per_episode.append({
            'map_path': map_rel_path,
            'env_type': env_type,
            'success': 1 if metrics['success'] else 0,
            'travel_distance': metrics['travel_distance'],
            'explored_rate': metrics['explored_rate'],
        })

    # Compute aggregates
    total = len(per_episode)
    explored_rates = [e['explored_rate'] for e in per_episode]
    success_rate = np.mean([e['success'] for e in per_episode])
    succ_dists = [e['travel_distance'] for e in per_episode if e['success'] == 1]
    travel_distance = float(np.mean(succ_dists)) if succ_dists else 0.0

    per_type = {}
    for et in ['room', 'tunnel', 'outdoor']:
        ep_list = [e for e in per_episode if e['env_type'] == et]
        if ep_list:
            s_rate = np.mean([e['success'] for e in ep_list])
            s_dists = [e['travel_distance'] for e in ep_list if e['success'] == 1]
            t_dist = float(np.mean(s_dists)) if s_dists else 0.0
            e_rate = float(np.mean([e['explored_rate'] for e in ep_list]))
            per_type[et] = {
                'explored_rate': e_rate,
                'travel_distance': t_dist,
                'success_rate': float(s_rate),
            }

    result = {
        'explored_rate': float(np.mean(explored_rates)),
        'travel_distance': travel_distance,
        'success_rate': float(success_rate),
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': total,
    }

    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)


if __name__ == '__main__':
    main()
